import re
from collections import defaultdict

def extract_word(question):
    q = question.strip()
    # Remove [user] prefix if present
    if q.startswith("[user]"):
        q = q[6:].strip()
    # Remove trailing question mark
    q = q.rstrip("?")

    # Pattern: "What does (the|a|an) WORD (look|sound|taste|smell) like"
    m = re.search(r'^What does (?:the|a|an)\s+(.+?)\s+(?:look|sound|taste|smell)\s+like$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What do WORD look like" (e.g. trousers, babies, feet)
    m = re.search(r'^What do\s+(.+?)\s+look\s+like$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What does WORD mean/look/sound/taste/smell"
    m = re.search(r'^What does\s+(.+?)\s+(?:mean|look|sound|taste|smell)$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What is (a|an) WORD"  or  "what is WORD"
    m = re.search(r'^[Ww]hat\s+is\s+(?:a|an\s+)?(.+)$', q)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What is WORD like"
    m = re.search(r'^What is\s+(.+?)\s+like$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What happens to (a|an) WORD"
    m = re.search(r'^What happens to (?:a|an)\s+(.+)$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "Where can you find (a|an) WORD"
    m = re.search(r'^Where can you find (?:a|an)\s+(.+)$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What does (the|a|an) WORD look like?" — alternate, WORD might have hyphen
    m = re.search(r'^What does (?:the|a|an)\s+(.+?)\s+(?:look|sound|taste|smell)\s+like$', q, re.IGNORECASE)
    if m:
        return m.group(1).strip().lower()

    # Pattern: "What is Scissoring?" etc.
    m = re.search(r'^[Ww]hat\s+is\s+(.+)$', q)
    if m:
        return m.group(1).strip().lower()

    return None

# Read input
with open("tmp/rename_list.txt", "r") as f:
    lines = f.readlines()

# Track per-phase word counts for dedup
phase_word_counts = defaultdict(lambda: defaultdict(int))

output_lines = []

for line in lines:
    line = line.strip()
    if not line:
        continue
    parts = line.split("\t", 1)
    if len(parts) != 2:
        continue
    path, question = parts[0], parts[1]

    word = extract_word(question)
    if word is None:
        print(f"WARNING: could not extract word from: {question}")
        word = "unknown"

    # Extract phase folder from path
    phase_match = re.search(r'(phase_\d+)', path)
    phase = phase_match.group(1) if phase_match else "unknown"

    # Track count for dedup within same phase
    phase_word_counts[phase][word] += 1
    count = phase_word_counts[phase][word]

    # Build new filename
    if count == 1:
        new_filename = f"{word}.md"
    else:
        new_filename = f"{word}_{count}.md"

    # Replace filename in path
    dir_part = "/".join(path.split("/")[:-1])
    output_lines.append(f"{dir_part}/{new_filename}")

# Write output
with open("tmp/rename_map.txt", "w") as f:
    for line in output_lines:
        f.write(line + "\n")

print(f"Processed {len(output_lines)} lines")
print(f"Wrote tmp/rename_map.txt")

